@implementation CodeTemplateManager

+ (instancetype)sharedManager {
    static CodeTemplateManager *sharedInstance = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken, ^{
        sharedInstance = [[self alloc] init];
    });
    return sharedInstance;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        [self loadTemplates];
    }
    return self;
}

