                @"code": @"// 运行时方法枚举模板\n%hook TargetClass\n\n+ (void)load {\n    [self enumerateClassInfo];\n}\n\n%new\n+ (void)enumerateClassInfo {\n    Class targetClass = [self class];\n    \n    NSLog(@\"[RUNTIME] Analyzing class: %@\", NSStringFromClass(targetClass));\n    \n    // 枚举实例方法\n    unsigned int methodCount;\n    Method *methods = class_copyMethodList(targetClass, &methodCount);\n    NSLog(@\"[RUNTIME] Instance methods (%d):\", methodCount);\n    \n    for (unsigned int i = 0; i < methodCount; i++) {\n        Method method = methods[i];\n        SEL selector = method_getName(method);\n        const char *typeEncoding = method_getTypeEncoding(method);\n        NSLog(@\"[RUNTIME] - %@ (%s)\", NSStringFromSelector(selector), typeEncoding);\n    }\n    free(methods);\n    \n    // 枚举类方法\n    methods = class_copyMethodList(object_getClass(targetClass), &methodCount);\n    NSLog(@\"[RUNTIME] Class methods (%d):\", methodCount);\n    \n    for (unsigned int i = 0; i < methodCount; i++) {\n        Method method = methods[i];\n        SEL selector = method_getName(method);\n        NSLog(@\"[RUNTIME] + %@\", NSStringFromSelector(selector));\n    }\n    free(methods);\n    \n    // 枚举属性\n    unsigned int propertyCount;\n    objc_property_t *properties = class_copyPropertyList(targetClass, &propertyCount);\n    NSLog(@\"[RUNTIME] Properties (%d):\", propertyCount);\n    \n    for (unsigned int i = 0; i < propertyCount; i++) {\n        objc_property_t property = properties[i];\n        const char *name = property_getName(property);\n        const char *attributes = property_getAttributes(property);\n        NSLog(@\"[RUNTIME] @property %s (%s)\", name, attributes);\n    }\n    free(properties);\n}\n\n%end\n"
