                @"code": @"// 文件操作监控模板\n%hook NSFileManager\n\n- (BOOL)createFileAtPath:(NSString *)path contents:(NSData *)data attributes:(NSDictionary *)attr {\n    NSLog(@\"[FILE] Creating file at: %@\", path);\n    if (data) {\n        NSLog(@\"[FILE] File size: %lu bytes\", (unsigned long)data.length);\n        // 如果是文本文件，打印内容\n        NSString *content = [[NSString alloc] initWithData:data encoding:NSUTF8StringEncoding];\n        if (content) {\n            NSLog(@\"[FILE] Content preview: %@\", [content substringToIndex:MIN(100, content.length)]);\n        }\n    }\n    \n    BOOL result = %orig;\n    NSLog(@\"[FILE] Create result: %@\", result ? @\"SUCCESS\" : @\"FAILED\");\n    \n    return result;\n}\n\n- (NSData *)contentsAtPath:(NSString *)path {\n    NSLog(@\"[FILE] Reading file at: %@\", path);\n    \n    NSData *result = %orig;\n    if (result) {\n        NSLog(@\"[FILE] Read %lu bytes\", (unsigned long)result.length);\n    } else {\n        NSLog(@\"[FILE] Failed to read file\");\n    }\n    \n    return result;\n}\n\n- (BOOL)removeItemAtPath:(NSString *)path error:(NSError **)error {\n    NSLog(@\"[FILE] Deleting file at: %@\", path);\n    \n    BOOL result = %orig;\n    NSLog(@\"[FILE] Delete result: %@\", result ? @\"SUCCESS\" : @\"FAILED\");\n    \n    return result;\n}\n\n%end\n"
