                @"title": @"自定义Toast提示",
                @"description": @"创建自定义Toast提示框",
                @"code": @"// 自定义Toast提示模板\nvoid showToast(NSString *message, UIView *parentView, CGFloat duration) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建Toast容器\n    UIView *toastView = [[UIView alloc] init];\n    toastView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.8];\n    toastView.layer.cornerRadius = 25;\n    toastView.layer.masksToBounds = YES;\n    toastView.alpha = 0.0;\n    \n    // 创建文本标签\n    UILabel *messageLabel = [[UILabel alloc] init];\n    messageLabel.text = message;\n    messageLabel.textColor = [UIColor whiteColor];\n    messageLabel.font = [UIFont systemFontOfSize:16 weight:UIFontWeightMedium];\n    messageLabel.textAlignment = NSTextAlignmentCenter;\n    messageLabel.numberOfLines = 0;\n    messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    [toastView addSubview:messageLabel];\n    [parentView addSubview:toastView];\n    \n    // 设置约束\n    toastView.translatesAutoresizingMaskIntoConstraints = NO;\n    [NSLayoutConstraint activateConstraints:@[\n        [messageLabel.topAnchor constraintEqualToAnchor:toastView.topAnchor constant:15],\n        [messageLabel.bottomAnchor constraintEqualToAnchor:toastView.bottomAnchor constant:-15],\n        [messageLabel.leadingAnchor constraintEqualToAnchor:toastView.leadingAnchor constant:20],\n        [messageLabel.trailingAnchor constraintEqualToAnchor:toastView.trailingAnchor constant:-20],\n        \n        [toastView.centerXAnchor constraintEqualToAnchor:parentView.centerXAnchor],\n        [toastView.bottomAnchor constraintEqualToAnchor:parentView.safeAreaLayoutGuide.bottomAnchor constant:-50],\n        [toastView.widthAnchor constraintLessThanOrEqualToConstant:300]\n    ]];\n    \n    // 显示动画\n    [UIView animateWithDuration:0.3 animations:^{\n        toastView.alpha = 1.0;\n    } completion:^(BOOL finished) {\n        // 自动隐藏\n        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(duration * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n            [UIView animateWithDuration:0.3 animations:^{\n                toastView.alpha = 0.0;\n            } completion:^(BOOL finished) {\n                [toastView removeFromSuperview];\n            }];\n        });\n    }];\n}\n\n// 使用示例\n// showToast(@\"操作成功！\", nil, 2.0);\n"
            },
            @{
                @"title": @"ActionSheet选择器",
                @"description": @"创建ActionSheet选择器弹窗",
                @"code": @"// ActionSheet选择器模板\nvoid showActionSheet(NSString *title, NSArray<NSString *> *options, UIViewController *presentingVC, void(^completion)(NSInteger selectedIndex)) {\n    UIAlertController *actionSheet = [UIAlertController alertControllerWithTitle:title\n                                                                         message:@\"请选择一个选项\"\n                                                                  preferredStyle:UIAlertControllerStyleActionSheet];\n    \n    // 添加选项\n    for (NSInteger i = 0; i < options.count; i++) {\n        NSString *option = options[i];\n        UIAlertAction *action = [UIAlertAction actionWithTitle:option\n                                                         style:UIAlertActionStyleDefault\n                                                       handler:^(UIAlertAction * _Nonnull action) {\n            if (completion) {\n                completion(i);\n            }\n        }];\n        [actionSheet addAction:action];\n    }\n    \n    // 添加取消按钮\n    UIAlertAction *cancelAction = [UIAlertAction actionWithTitle:@\"取消\"\n                                                           style:UIAlertActionStyleCancel\n                                                         handler:^(UIAlertAction * _Nonnull action) {\n        if (completion) {\n            completion(-1); // -1 表示取消\n        }\n    }];\n    [actionSheet addAction:cancelAction];\n    \n    // 获取当前视图控制器\n    if (!presentingVC) {\n        presentingVC = [UIApplication sharedApplication].keyWindow.rootViewController;\n        while (presentingVC.presentedViewController) {\n            presentingVC = presentingVC.presentedViewController;\n        }\n    }\n    \n    // iPad适配\n    if ([[UIDevice currentDevice] userInterfaceIdiom] == UIUserInterfaceIdiomPad) {\n        actionSheet.popoverPresentationController.sourceView = presentingVC.view;\n        actionSheet.popoverPresentationController.sourceRect = CGRectMake(presentingVC.view.bounds.size.width/2, presentingVC.view.bounds.size.height/2, 1, 1);\n    }\n    \n    [presentingVC presentViewController:actionSheet animated:YES completion:nil];\n}\n\n// 使用示例\n// NSArray *options = @[@\"选项1\", @\"选项2\", @\"选项3\"];\n// showActionSheet(@\"请选择\", options, nil, ^(NSInteger selectedIndex) {\n//     if (selectedIndex >= 0) {\n//         NSLog(@\"用户选择了: %@\", options[selectedIndex]);\n//     }\n// });\n"
            },
            @{
                @"title": @"进度提示弹窗",
                @"description": @"带进度条的加载提示弹窗",
                @"code": @"// 进度提示弹窗模板\n@interface ProgressHUD : UIView\n@property (nonatomic, strong) UIProgressView *progressView;\n@property (nonatomic, strong) UILabel *messageLabel;\n@property (nonatomic, strong) UIActivityIndicatorView *activityIndicator;\n+ (instancetype)showInView:(UIView *)view message:(NSString *)message;\n- (void)updateProgress:(float)progress;\n- (void)dismiss;\n@end\n\n@implementation ProgressHUD\n\n+ (instancetype)showInView:(UIView *)view message:(NSString *)message {\n    if (!view) {\n        view = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    ProgressHUD *hud = [[ProgressHUD alloc] initWithFrame:view.bounds];\n    hud.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.5];\n    \n    // 创建内容容器\n    UIView *contentView = [[UIView alloc] init];\n    contentView.backgroundColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:0.9];\n    contentView.layer.cornerRadius = 15;\n    contentView.translatesAutoresizingMaskIntoConstraints = NO;\n    [hud addSubview:contentView];\n    \n    // 创建活动指示器\n    hud.activityIndicator = [[UIActivityIndicatorView alloc] initWithActivityIndicatorStyle:UIActivityIndicatorViewStyleLarge];\n    hud.activityIndicator.color = [UIColor whiteColor];\n    hud.activityIndicator.translatesAutoresizingMaskIntoConstraints = NO;\n    [hud.activityIndicator startAnimating];\n    [contentView addSubview:hud.activityIndicator];\n    \n    // 创建进度条\n    hud.progressView = [[UIProgressView alloc] initWithProgressViewStyle:UIProgressViewStyleDefault];\n    hud.progressView.progressTintColor = [UIColor systemBlueColor];\n    hud.progressView.trackTintColor = [UIColor darkGrayColor];\n    hud.progressView.translatesAutoresizingMaskIntoConstraints = NO;\n    hud.progressView.hidden = YES;\n    [contentView addSubview:hud.progressView];\n    \n    // 创建消息标签\n    hud.messageLabel = [[UILabel alloc] init];\n    hud.messageLabel.text = message;\n    hud.messageLabel.textColor = [UIColor whiteColor];\n    hud.messageLabel.font = [UIFont systemFontOfSize:16];\n    hud.messageLabel.textAlignment = NSTextAlignmentCenter;\n    hud.messageLabel.numberOfLines = 0;\n    hud.messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    [contentView addSubview:hud.messageLabel];\n    \n    // 设置约束\n    [NSLayoutConstraint activateConstraints:@[\n        [contentView.centerXAnchor constraintEqualToAnchor:hud.centerXAnchor],\n        [contentView.centerYAnchor constraintEqualToAnchor:hud.centerYAnchor],\n        [contentView.widthAnchor constraintEqualToConstant:200],\n        [contentView.heightAnchor constraintEqualToConstant:150],\n        \n        [hud.activityIndicator.topAnchor constraintEqualToAnchor:contentView.topAnchor constant:20],\n        [hud.activityIndicator.centerXAnchor constraintEqualToAnchor:contentView.centerXAnchor],\n        \n        [hud.progressView.topAnchor constraintEqualToAnchor:hud.activityIndicator.bottomAnchor constant:15],\n        [hud.progressView.leadingAnchor constraintEqualToAnchor:contentView.leadingAnchor constant:20],\n        [hud.progressView.trailingAnchor constraintEqualToAnchor:contentView.trailingAnchor constant:-20],\n        \n        [hud.messageLabel.topAnchor constraintEqualToAnchor:hud.progressView.bottomAnchor constant:15],\n        [hud.messageLabel.leadingAnchor constraintEqualToAnchor:contentView.leadingAnchor constant:15],\n        [hud.messageLabel.trailingAnchor constraintEqualToAnchor:contentView.trailingAnchor constant:-15],\n        [hud.messageLabel.bottomAnchor constraintLessThanOrEqualToAnchor:contentView.bottomAnchor constant:-15]\n    ]];\n    \n    [view addSubview:hud];\n    \n    // 显示动画\n    hud.alpha = 0;\n    [UIView animateWithDuration:0.3 animations:^{\n        hud.alpha = 1;\n    }];\n    \n    return hud;\n}\n\n- (void)updateProgress:(float)progress {\n    dispatch_async(dispatch_get_main_queue(), ^{\n        self.progressView.hidden = NO;\n        [self.activityIndicator stopAnimating];\n        self.activityIndicator.hidden = YES;\n        \n        [self.progressView setProgress:progress animated:YES];\n        \n        if (progress >= 1.0) {\n            self.messageLabel.text = @\"完成！\";\n            dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n                [self dismiss];\n            });\n        }\n    });\n}\n\n- (void)dismiss {\n    [UIView animateWithDuration:0.3 animations:^{\n        self.alpha = 0;\n    } completion:^(BOOL finished) {\n        [self removeFromSuperview];\n    }];\n}\n\n@end\n\n// 使用示例\n// ProgressHUD *hud = [ProgressHUD showInView:nil message:@\"正在加载...\"];\n// \n// // 模拟进度更新\n// dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(1.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n//     [hud updateProgress:0.3];\n// });\n// \n// dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(2.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n//     [hud updateProgress:0.7];\n// });\n// \n// dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(3.0 * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n//     [hud updateProgress:1.0];\n// });\n"
            },
            @{
                @"title": @"卡片式弹窗",
                @"description": @"创建现代化的卡片式弹窗",
                @"code": @"// 卡片式弹窗模板\nvoid showCardPopup(NSString *title, NSString *message, UIView *parentView, void(^onConfirm)(void), void(^onCancel)(void)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.5];\n    overlayView.alpha = 0.0;\n    \n    // 创建卡片容器\n    UIView *cardView = [[UIView alloc] init];\n    cardView.backgroundColor = [UIColor colorWithRed:0.95 green:0.95 blue:0.97 alpha:1.0];\n    cardView.layer.cornerRadius = 20;\n    cardView.layer.shadowColor = [UIColor blackColor].CGColor;\n    cardView.layer.shadowOffset = CGSizeMake(0, 10);\n    cardView.layer.shadowOpacity = 0.3;\n    cardView.layer.shadowRadius = 20;\n    cardView.transform = CGAffineTransformMakeScale(0.7, 0.7);\n    cardView.alpha = 0.0;\n    \n    // 创建标题\n    UILabel *titleLabel = [[UILabel alloc] init];\n    titleLabel.text = title;\n    titleLabel.font = [UIFont boldSystemFontOfSize:22];\n    titleLabel.textColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0];\n    titleLabel.textAlignment = NSTextAlignmentCenter;\n    titleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建消息\n    UILabel *messageLabel = [[UILabel alloc] init];\n    messageLabel.text = message;\n    messageLabel.font = [UIFont systemFontOfSize:16];\n    messageLabel.textColor = [UIColor colorWithRed:0.4 green:0.4 blue:0.4 alpha:1.0];\n    messageLabel.textAlignment = NSTextAlignmentCenter;\n    messageLabel.numberOfLines = 0;\n    messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建按钮容器\n    UIView *buttonContainer = [[UIView alloc] init];\n    buttonContainer.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 确认按钮\n    UIButton *confirmButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [confirmButton setTitle:@\"确认\" forState:UIControlStateNormal];\n    confirmButton.backgroundColor = [UIColor systemBlueColor];\n    [confirmButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];\n    confirmButton.titleLabel.font = [UIFont boldSystemFontOfSize:16];\n    confirmButton.layer.cornerRadius = 12;\n    confirmButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 取消按钮\n    UIButton *cancelButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [cancelButton setTitle:@\"取消\" forState:UIControlStateNormal];\n    cancelButton.backgroundColor = [UIColor colorWithRed:0.9 green:0.9 blue:0.9 alpha:1.0];\n    [cancelButton setTitleColor:[UIColor colorWithRed:0.4 green:0.4 blue:0.4 alpha:1.0] forState:UIControlStateNormal];\n    cancelButton.titleLabel.font = [UIFont systemFontOfSize:16];\n    cancelButton.layer.cornerRadius = 12;\n    cancelButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 添加子视图\n    [cardView addSubview:titleLabel];\n    [cardView addSubview:messageLabel];\n    [cardView addSubview:buttonContainer];\n    [buttonContainer addSubview:confirmButton];\n    [buttonContainer addSubview:cancelButton];\n    [overlayView addSubview:cardView];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    cardView.translatesAutoresizingMaskIntoConstraints = NO;\n    [NSLayoutConstraint activateConstraints:@[\n        // 卡片约束\n        [cardView.centerXAnchor constraintEqualToAnchor:overlayView.centerXAnchor],\n        [cardView.centerYAnchor constraintEqualToAnchor:overlayView.centerYAnchor],\n        [cardView.widthAnchor constraintEqualToConstant:300],\n        [cardView.heightAnchor constraintEqualToConstant:200],\n        \n        // 标题约束\n        [titleLabel.topAnchor constraintEqualToAnchor:cardView.topAnchor constant:25],\n        [titleLabel.leadingAnchor constraintEqualToAnchor:cardView.leadingAnchor constant:20],\n        [titleLabel.trailingAnchor constraintEqualToAnchor:cardView.trailingAnchor constant:-20],\n        \n        // 消息约束\n        [messageLabel.topAnchor constraintEqualToAnchor:titleLabel.bottomAnchor constant:15],\n        [messageLabel.leadingAnchor constraintEqualToAnchor:cardView.leadingAnchor constant:20],\n        [messageLabel.trailingAnchor constraintEqualToAnchor:cardView.trailingAnchor constant:-20],\n        \n        // 按钮容器约束\n        [buttonContainer.bottomAnchor constraintEqualToAnchor:cardView.bottomAnchor constant:-20],\n        [buttonContainer.leadingAnchor constraintEqualToAnchor:cardView.leadingAnchor constant:20],\n        [buttonContainer.trailingAnchor constraintEqualToAnchor:cardView.trailingAnchor constant:-20],\n        [buttonContainer.heightAnchor constraintEqualToConstant:44],\n        \n        // 按钮约束\n        [cancelButton.leadingAnchor constraintEqualToAnchor:buttonContainer.leadingAnchor],\n        [cancelButton.topAnchor constraintEqualToAnchor:buttonContainer.topAnchor],\n        [cancelButton.bottomAnchor constraintEqualToAnchor:buttonContainer.bottomAnchor],\n        [cancelButton.widthAnchor constraintEqualToConstant:120],\n        \n        [confirmButton.trailingAnchor constraintEqualToAnchor:buttonContainer.trailingAnchor],\n        [confirmButton.topAnchor constraintEqualToAnchor:buttonContainer.topAnchor],\n        [confirmButton.bottomAnchor constraintEqualToAnchor:buttonContainer.bottomAnchor],\n        [confirmButton.widthAnchor constraintEqualToConstant:120]\n    ]];\n    \n    // 按钮事件\n    [confirmButton addTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            cardView.transform = CGAffineTransformMakeScale(0.7, 0.7);\n            cardView.alpha = 0.0;\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n            if (onConfirm) onConfirm();\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    [cancelButton addTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            cardView.transform = CGAffineTransformMakeScale(0.7, 0.7);\n            cardView.alpha = 0.0;\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n            if (onCancel) onCancel();\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 显示动画\n    [UIView animateWithDuration:0.3 delay:0 usingSpringWithDamping:0.8 initialSpringVelocity:0.5 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        cardView.transform = CGAffineTransformIdentity;\n        cardView.alpha = 1.0;\n    } completion:nil];\n}\n\n// 使用示例\n// showCardPopup(@\"提示\", @\"确定要执行此操作吗？\", nil, ^{\n//     NSLog(@\"用户点击了确认\");\n// }, ^{\n//     NSLog(@\"用户点击了取消\");\n// });\n"
            },
            @{
                @"title": @"底部滑出弹窗",
                @"description": @"从底部滑出的弹窗视图",
                @"code": @"// 底部滑出弹窗模板\nvoid showBottomSheetPopup(NSString *title, NSArray<NSString *> *options, UIView *parentView, void(^onSelect)(NSInteger index)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.5];\n    overlayView.alpha = 0.0;\n    \n    // 创建底部弹窗容器\n    UIView *sheetView = [[UIView alloc] init];\n    sheetView.backgroundColor = [UIColor whiteColor];\n    sheetView.layer.cornerRadius = 20;\n    sheetView.layer.maskedCorners = kCALayerMinXMinYCorner | kCALayerMaxXMinYCorner;\n    \n    // 创建拖拽指示器\n    UIView *dragIndicator = [[UIView alloc] init];\n    dragIndicator.backgroundColor = [UIColor colorWithRed:0.8 green:0.8 blue:0.8 alpha:1.0];\n    dragIndicator.layer.cornerRadius = 2.5;\n    dragIndicator.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建标题\n    UILabel *titleLabel = [[UILabel alloc] init];\n    titleLabel.text = title;\n    titleLabel.font = [UIFont boldSystemFontOfSize:18];\n    titleLabel.textColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0];\n    titleLabel.textAlignment = NSTextAlignmentCenter;\n    titleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建选项容器\n    UIScrollView *optionsScrollView = [[UIScrollView alloc] init];\n    optionsScrollView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UIStackView *optionsStackView = [[UIStackView alloc] init];\n    optionsStackView.axis = UILayoutConstraintAxisVertical;\n    optionsStackView.spacing = 0;\n    optionsStackView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 添加选项按钮\n    for (NSInteger i = 0; i < options.count; i++) {\n        UIButton *optionButton = [UIButton buttonWithType:UIButtonTypeSystem];\n        [optionButton setTitle:options[i] forState:UIControlStateNormal];\n        optionButton.titleLabel.font = [UIFont systemFontOfSize:16];\n        [optionButton setTitleColor:[UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0] forState:UIControlStateNormal];\n        optionButton.backgroundColor = [UIColor clearColor];\n        optionButton.contentHorizontalAlignment = UIControlContentHorizontalAlignmentLeft;\n        optionButton.contentEdgeInsets = UIEdgeInsetsMake(0, 20, 0, 20);\n        \n        // 添加分割线\n        if (i < options.count - 1) {\n            UIView *separator = [[UIView alloc] init];\n            separator.backgroundColor = [UIColor colorWithRed:0.9 green:0.9 blue:0.9 alpha:1.0];\n            separator.translatesAutoresizingMaskIntoConstraints = NO;\n            [optionButton addSubview:separator];\n            \n            [NSLayoutConstraint activateConstraints:@[\n                [separator.leadingAnchor constraintEqualToAnchor:optionButton.leadingAnchor constant:20],\n                [separator.trailingAnchor constraintEqualToAnchor:optionButton.trailingAnchor constant:-20],\n                [separator.bottomAnchor constraintEqualToAnchor:optionButton.bottomAnchor],\n                [separator.heightAnchor constraintEqualToConstant:0.5]\n            ]];\n        }\n        \n        [optionButton addTarget:^{\n            [UIView animateWithDuration:0.3 animations:^{\n                overlayView.alpha = 0.0;\n                sheetView.transform = CGAffineTransformMakeTranslation(0, sheetView.frame.size.height);\n            } completion:^(BOOL finished) {\n                [overlayView removeFromSuperview];\n                if (onSelect) onSelect(i);\n            }];\n        } forControlEvents:UIControlEventTouchUpInside];\n        \n        [optionButton setTranslatesAutoresizingMaskIntoConstraints:NO];\n        [optionButton.heightAnchor constraintEqualToConstant:50].active = YES;\n        \n        [optionsStackView addArrangedSubview:optionButton];\n    }\n    \n    // 添加取消按钮\n    UIButton *cancelButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [cancelButton setTitle:@\"取消\" forState:UIControlStateNormal];\n    cancelButton.titleLabel.font = [UIFont boldSystemFontOfSize:16];\n    [cancelButton setTitleColor:[UIColor systemRedColor] forState:UIControlStateNormal];\n    cancelButton.backgroundColor = [UIColor colorWithRed:0.98 green:0.98 blue:0.98 alpha:1.0];\n    cancelButton.layer.cornerRadius = 12;\n    cancelButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    [cancelButton addTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            sheetView.transform = CGAffineTransformMakeTranslation(0, sheetView.frame.size.height);\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 添加子视图\n    [optionsScrollView addSubview:optionsStackView];\n    [sheetView addSubview:dragIndicator];\n    [sheetView addSubview:titleLabel];\n    [sheetView addSubview:optionsScrollView];\n    [sheetView addSubview:cancelButton];\n    [overlayView addSubview:sheetView];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    sheetView.translatesAutoresizingMaskIntoConstraints = NO;\n    CGFloat sheetHeight = MIN(400, 150 + options.count * 50);\n    \n    [NSLayoutConstraint activateConstraints:@[\n        // 弹窗约束\n        [sheetView.leadingAnchor constraintEqualToAnchor:overlayView.leadingAnchor],\n        [sheetView.trailingAnchor constraintEqualToAnchor:overlayView.trailingAnchor],\n        [sheetView.bottomAnchor constraintEqualToAnchor:overlayView.bottomAnchor],\n        [sheetView.heightAnchor constraintEqualToConstant:sheetHeight],\n        \n        // 拖拽指示器约束\n        [dragIndicator.topAnchor constraintEqualToAnchor:sheetView.topAnchor constant:10],\n        [dragIndicator.centerXAnchor constraintEqualToAnchor:sheetView.centerXAnchor],\n        [dragIndicator.widthAnchor constraintEqualToConstant:40],\n        [dragIndicator.heightAnchor constraintEqualToConstant:5],\n        \n        // 标题约束\n        [titleLabel.topAnchor constraintEqualToAnchor:dragIndicator.bottomAnchor constant:15],\n        [titleLabel.leadingAnchor constraintEqualToAnchor:sheetView.leadingAnchor constant:20],\n        [titleLabel.trailingAnchor constraintEqualToAnchor:sheetView.trailingAnchor constant:-20],\n        \n        // 选项滚动视图约束\n        [optionsScrollView.topAnchor constraintEqualToAnchor:titleLabel.bottomAnchor constant:20],\n        [optionsScrollView.leadingAnchor constraintEqualToAnchor:sheetView.leadingAnchor],\n        [optionsScrollView.trailingAnchor constraintEqualToAnchor:sheetView.trailingAnchor],\n        [optionsScrollView.bottomAnchor constraintEqualToAnchor:cancelButton.topAnchor constant:-20],\n        \n        // 选项堆栈视图约束\n        [optionsStackView.topAnchor constraintEqualToAnchor:optionsScrollView.topAnchor],\n        [optionsStackView.leadingAnchor constraintEqualToAnchor:optionsScrollView.leadingAnchor],\n        [optionsStackView.trailingAnchor constraintEqualToAnchor:optionsScrollView.trailingAnchor],\n        [optionsStackView.bottomAnchor constraintEqualToAnchor:optionsScrollView.bottomAnchor],\n        [optionsStackView.widthAnchor constraintEqualToAnchor:optionsScrollView.widthAnchor],\n        \n        // 取消按钮约束\n        [cancelButton.leadingAnchor constraintEqualToAnchor:sheetView.leadingAnchor constant:20],\n        [cancelButton.trailingAnchor constraintEqualToAnchor:sheetView.trailingAnchor constant:-20],\n        [cancelButton.bottomAnchor constraintEqualToAnchor:sheetView.safeAreaLayoutGuide.bottomAnchor constant:-20],\n        [cancelButton.heightAnchor constraintEqualToConstant:50]\n    ]];\n    \n    // 初始位置设置为底部外\n    sheetView.transform = CGAffineTransformMakeTranslation(0, sheetHeight);\n    \n    // 显示动画\n    [UIView animateWithDuration:0.4 delay:0 usingSpringWithDamping:0.8 initialSpringVelocity:0.5 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        sheetView.transform = CGAffineTransformIdentity;\n    } completion:nil];\n}\n\n// 使用示例\n// NSArray *options = @[@\"选项1\", @\"选项2\", @\"选项3\", @\"选项4\"];\n// showBottomSheetPopup(@\"请选择操作\", options, nil, ^(NSInteger index) {\n//     NSLog(@\"用户选择了: %@\", options[index]);\n// });\n"
            },
