                @"title": @"侧边滑入弹窗",
                @"description": @"从侧边滑入的抽屉式弹窗",
                @"code": @"// 侧边滑入弹窗模板\nvoid showSideDrawerPopup(NSString *title, NSArray<NSDictionary *> *menuItems, UIView *parentView, void(^onItemSelect)(NSInteger index)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.5];\n    overlayView.alpha = 0.0;\n    \n    // 创建侧边抽屉\n    UIView *drawerView = [[UIView alloc] init];\n    drawerView.backgroundColor = [UIColor colorWithRed:0.98 green:0.98 blue:1.0 alpha:1.0];\n    drawerView.layer.shadowColor = [UIColor blackColor].CGColor;\n    drawerView.layer.shadowOffset = CGSizeMake(2, 0);\n    drawerView.layer.shadowOpacity = 0.3;\n    drawerView.layer.shadowRadius = 10;\n    \n    // 创建头部视图\n    UIView *headerView = [[UIView alloc] init];\n    headerView.backgroundColor = [UIColor systemBlueColor];\n    headerView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建标题\n    UILabel *titleLabel = [[UILabel alloc] init];\n    titleLabel.text = title;\n    titleLabel.font = [UIFont boldSystemFontOfSize:20];\n    titleLabel.textColor = [UIColor whiteColor];\n    titleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建关闭按钮\n    UIButton *closeButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    if (@available(iOS 13.0, *)) {\n        [closeButton setImage:[UIImage systemImageNamed:@\"xmark\"] forState:UIControlStateNormal];\n    } else {\n        [closeButton setTitle:@\"✕\" forState:UIControlStateNormal];\n    }\n    [closeButton setTintColor:[UIColor whiteColor]];\n    closeButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建菜单容器\n    UIScrollView *menuScrollView = [[UIScrollView alloc] init];\n    menuScrollView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UIStackView *menuStackView = [[UIStackView alloc] init];\n    menuStackView.axis = UILayoutConstraintAxisVertical;\n    menuStackView.spacing = 0;\n    menuStackView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 添加菜单项\n    for (NSInteger i = 0; i < menuItems.count; i++) {\n        NSDictionary *item = menuItems[i];\n        NSString *itemTitle = item[@\"title\"] ?: @\"\";\n        NSString *itemIcon = item[@\"icon\"] ?: @\"\";\n        \n        UIView *menuItemView = [[UIView alloc] init];\n        menuItemView.backgroundColor = [UIColor clearColor];\n        menuItemView.translatesAutoresizingMaskIntoConstraints = NO;\n        \n        // 创建图标\n        UIImageView *iconView = [[UIImageView alloc] init];\n        if (@available(iOS 13.0, *) && itemIcon.length > 0) {\n            iconView.image = [UIImage systemImageNamed:itemIcon];\n        }\n        iconView.tintColor = [UIColor systemBlueColor];\n        iconView.contentMode = UIViewContentModeScaleAspectFit;\n        iconView.translatesAutoresizingMaskIntoConstraints = NO;\n        \n        // 创建标题标签\n        UILabel *itemLabel = [[UILabel alloc] init];\n        itemLabel.text = itemTitle;\n        itemLabel.font = [UIFont systemFontOfSize:16];\n        itemLabel.textColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0];\n        itemLabel.translatesAutoresizingMaskIntoConstraints = NO;\n        \n        // 创建点击按钮\n        UIButton *itemButton = [UIButton buttonWithType:UIButtonTypeSystem];\n        itemButton.backgroundColor = [UIColor clearColor];\n        itemButton.translatesAutoresizingMaskIntoConstraints = NO;\n        \n        [itemButton addTarget:^{\n            [UIView animateWithDuration:0.3 animations:^{\n                overlayView.alpha = 0.0;\n                drawerView.transform = CGAffineTransformMakeTranslation(-280, 0);\n            } completion:^(BOOL finished) {\n                [overlayView removeFromSuperview];\n                if (onItemSelect) onItemSelect(i);\n            }];\n        } forControlEvents:UIControlEventTouchUpInside];\n        \n        // 添加悬停效果\n        [itemButton addTarget:^{\n            [UIView animateWithDuration:0.2 animations:^{\n                menuItemView.backgroundColor = [UIColor colorWithRed:0.95 green:0.95 blue:0.95 alpha:1.0];\n            }];\n        } forControlEvents:UIControlEventTouchDown];\n        \n        [itemButton addTarget:^{\n            [UIView animateWithDuration:0.2 animations:^{\n                menuItemView.backgroundColor = [UIColor clearColor];\n            }];\n        } forControlEvents:UIControlEventTouchUpInside | UIControlEventTouchUpOutside | UIControlEventTouchCancel];\n        \n        // 添加分割线\n        UIView *separator = [[UIView alloc] init];\n        separator.backgroundColor = [UIColor colorWithRed:0.9 green:0.9 blue:0.9 alpha:1.0];\n        separator.translatesAutoresizingMaskIntoConstraints = NO;\n        \n        // 组装菜单项\n        [menuItemView addSubview:iconView];\n        [menuItemView addSubview:itemLabel];\n        [menuItemView addSubview:itemButton];\n        [menuItemView addSubview:separator];\n        \n        [NSLayoutConstraint activateConstraints:@[\n            [menuItemView.heightAnchor constraintEqualToConstant:60],\n            \n            [iconView.leadingAnchor constraintEqualToAnchor:menuItemView.leadingAnchor constant:20],\n            [iconView.centerYAnchor constraintEqualToAnchor:menuItemView.centerYAnchor],\n            [iconView.widthAnchor constraintEqualToConstant:24],\n            [iconView.heightAnchor constraintEqualToConstant:24],\n            \n            [itemLabel.leadingAnchor constraintEqualToAnchor:iconView.trailingAnchor constant:15],\n            [itemLabel.centerYAnchor constraintEqualToAnchor:menuItemView.centerYAnchor],\n            [itemLabel.trailingAnchor constraintEqualToAnchor:menuItemView.trailingAnchor constant:-20],\n            \n            [itemButton.topAnchor constraintEqualToAnchor:menuItemView.topAnchor],\n            [itemButton.leadingAnchor constraintEqualToAnchor:menuItemView.leadingAnchor],\n            [itemButton.trailingAnchor constraintEqualToAnchor:menuItemView.trailingAnchor],\n            [itemButton.bottomAnchor constraintEqualToAnchor:menuItemView.bottomAnchor],\n            \n            [separator.leadingAnchor constraintEqualToAnchor:menuItemView.leadingAnchor constant:20],\n            [separator.trailingAnchor constraintEqualToAnchor:menuItemView.trailingAnchor],\n            [separator.bottomAnchor constraintEqualToAnchor:menuItemView.bottomAnchor],\n            [separator.heightAnchor constraintEqualToConstant:0.5]\n        ]];\n        \n        [menuStackView addArrangedSubview:menuItemView];\n    }\n    \n    // 关闭按钮事件\n    [closeButton addTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            drawerView.transform = CGAffineTransformMakeTranslation(-280, 0);\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 点击遮罩关闭\n    UITapGestureRecognizer *tapGesture = [[UITapGestureRecognizer alloc] initWithTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            drawerView.transform = CGAffineTransformMakeTranslation(-280, 0);\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n        }];\n    } action:@selector(invoke)];\n    [overlayView addGestureRecognizer:tapGesture];\n    \n    // 添加子视图\n    [headerView addSubview:titleLabel];\n    [headerView addSubview:closeButton];\n    [menuScrollView addSubview:menuStackView];\n    [drawerView addSubview:headerView];\n    [drawerView addSubview:menuScrollView];\n    [overlayView addSubview:drawerView];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    drawerView.translatesAutoresizingMaskIntoConstraints = NO;\n    [NSLayoutConstraint activateConstraints:@[\n        // 抽屉约束\n        [drawerView.leadingAnchor constraintEqualToAnchor:overlayView.leadingAnchor],\n        [drawerView.topAnchor constraintEqualToAnchor:overlayView.topAnchor],\n        [drawerView.bottomAnchor constraintEqualToAnchor:overlayView.bottomAnchor],\n        [drawerView.widthAnchor constraintEqualToConstant:280],\n        \n        // 头部视图约束\n        [headerView.topAnchor constraintEqualToAnchor:drawerView.topAnchor],\n        [headerView.leadingAnchor constraintEqualToAnchor:drawerView.leadingAnchor],\n        [headerView.trailingAnchor constraintEqualToAnchor:drawerView.trailingAnchor],\n        [headerView.heightAnchor constraintEqualToConstant:100],\n        \n        // 标题约束\n        [titleLabel.leadingAnchor constraintEqualToAnchor:headerView.leadingAnchor constant:20],\n        [titleLabel.bottomAnchor constraintEqualToAnchor:headerView.bottomAnchor constant:-20],\n        \n        // 关闭按钮约束\n        [closeButton.trailingAnchor constraintEqualToAnchor:headerView.trailingAnchor constant:-20],\n        [closeButton.bottomAnchor constraintEqualToAnchor:headerView.bottomAnchor constant:-20],\n        [closeButton.widthAnchor constraintEqualToConstant:30],\n        [closeButton.heightAnchor constraintEqualToConstant:30],\n        \n        // 菜单滚动视图约束\n        [menuScrollView.topAnchor constraintEqualToAnchor:headerView.bottomAnchor],\n        [menuScrollView.leadingAnchor constraintEqualToAnchor:drawerView.leadingAnchor],\n        [menuScrollView.trailingAnchor constraintEqualToAnchor:drawerView.trailingAnchor],\n        [menuScrollView.bottomAnchor constraintEqualToAnchor:drawerView.bottomAnchor],\n        \n        // 菜单堆栈视图约束\n        [menuStackView.topAnchor constraintEqualToAnchor:menuScrollView.topAnchor],\n        [menuStackView.leadingAnchor constraintEqualToAnchor:menuScrollView.leadingAnchor],\n        [menuStackView.trailingAnchor constraintEqualToAnchor:menuScrollView.trailingAnchor],\n        [menuStackView.bottomAnchor constraintEqualToAnchor:menuScrollView.bottomAnchor],\n        [menuStackView.widthAnchor constraintEqualToAnchor:menuScrollView.widthAnchor]\n    ]];\n    \n    // 初始位置设置为左侧外\n    drawerView.transform = CGAffineTransformMakeTranslation(-280, 0);\n    \n    // 显示动画\n    [UIView animateWithDuration:0.4 delay:0 usingSpringWithDamping:0.8 initialSpringVelocity:0.5 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        drawerView.transform = CGAffineTransformIdentity;\n    } completion:nil];\n}\n\n// 使用示例\n// NSArray *menuItems = @[\n//     @{@\"title\": @\"首页\", @\"icon\": @\"house\"},\n//     @{@\"title\": @\"设置\", @\"icon\": @\"gear\"},\n//     @{@\"title\": @\"关于\", @\"icon\": @\"info.circle\"}\n// ];\n// showSideDrawerPopup(@\"菜单\", menuItems, nil, ^(NSInteger index) {\n//     NSLog(@\"用户选择了菜单项: %ld\", (long)index);\n// });\n"
            },
            @{
                @"title": @"浮动气泡弹窗",
                @"description": @"带箭头的浮动气泡提示弹窗",
                @"code": @"// 浮动气泡弹窗模板\nvoid showBubblePopup(NSString *message, UIView *anchorView, UIView *parentView, CGFloat duration) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建气泡容器\n    UIView *bubbleContainer = [[UIView alloc] init];\n    bubbleContainer.backgroundColor = [UIColor clearColor];\n    bubbleContainer.alpha = 0.0;\n    \n    // 创建气泡主体\n    UIView *bubbleView = [[UIView alloc] init];\n    bubbleView.backgroundColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:0.9];\n    bubbleView.layer.cornerRadius = 12;\n    bubbleView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建箭头\n    UIView *arrowView = [[UIView alloc] init];\n    arrowView.backgroundColor = [UIColor clearColor];\n    arrowView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 绘制箭头\n    CAShapeLayer *arrowLayer = [CAShapeLayer layer];\n    UIBezierPath *arrowPath = [UIBezierPath bezierPath];\n    [arrowPath moveToPoint:CGPointMake(0, 0)];\n    [arrowPath addLineToPoint:CGPointMake(10, 10)];\n    [arrowPath addLineToPoint:CGPointMake(20, 0)];\n    [arrowPath closePath];\n    \n    arrowLayer.path = arrowPath.CGPath;\n    arrowLayer.fillColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:0.9].CGColor;\n    [arrowView.layer addSublayer:arrowLayer];\n    \n    // 创建消息标签\n    UILabel *messageLabel = [[UILabel alloc] init];\n    messageLabel.text = message;\n    messageLabel.textColor = [UIColor whiteColor];\n    messageLabel.font = [UIFont systemFontOfSize:14];\n    messageLabel.textAlignment = NSTextAlignmentCenter;\n    messageLabel.numberOfLines = 0;\n    messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 添加子视图\n    [bubbleView addSubview:messageLabel];\n    [bubbleContainer addSubview:bubbleView];\n    [bubbleContainer addSubview:arrowView];\n    [parentView addSubview:bubbleContainer];\n    \n    // 计算位置\n    CGRect anchorFrame = [anchorView convertRect:anchorView.bounds toView:parentView];\n    CGFloat bubbleWidth = MIN(200, parentView.bounds.size.width - 40);\n    CGFloat bubbleHeight = 60;\n    \n    // 设置气泡容器约束\n    bubbleContainer.translatesAutoresizingMaskIntoConstraints = NO;\n    [NSLayoutConstraint activateConstraints:@[\n        [bubbleContainer.centerXAnchor constraintEqualToAnchor:parentView.leadingAnchor constant:CGRectGetMidX(anchorFrame)],\n        [bubbleContainer.bottomAnchor constraintEqualToAnchor:parentView.topAnchor constant:CGRectGetMinY(anchorFrame) - 10],\n        [bubbleContainer.widthAnchor constraintEqualToConstant:bubbleWidth],\n        [bubbleContainer.heightAnchor constraintEqualToConstant:bubbleHeight + 10]\n    ]];\n    \n    // 设置气泡主体约束\n    [NSLayoutConstraint activateConstraints:@[\n        [bubbleView.topAnchor constraintEqualToAnchor:bubbleContainer.topAnchor],\n        [bubbleView.leadingAnchor constraintEqualToAnchor:bubbleContainer.leadingAnchor],\n        [bubbleView.trailingAnchor constraintEqualToAnchor:bubbleContainer.trailingAnchor],\n        [bubbleView.heightAnchor constraintEqualToConstant:bubbleHeight]\n    ]];\n    \n    // 设置箭头约束\n    [NSLayoutConstraint activateConstraints:@[\n        [arrowView.topAnchor constraintEqualToAnchor:bubbleView.bottomAnchor],\n        [arrowView.centerXAnchor constraintEqualToAnchor:bubbleView.centerXAnchor],\n        [arrowView.widthAnchor constraintEqualToConstant:20],\n        [arrowView.heightAnchor constraintEqualToConstant:10]\n    ]];\n    \n    // 设置消息标签约束\n    [NSLayoutConstraint activateConstraints:@[\n        [messageLabel.topAnchor constraintEqualToAnchor:bubbleView.topAnchor constant:10],\n        [messageLabel.leadingAnchor constraintEqualToAnchor:bubbleView.leadingAnchor constant:15],\n        [messageLabel.trailingAnchor constraintEqualToAnchor:bubbleView.trailingAnchor constant:-15],\n        [messageLabel.bottomAnchor constraintEqualToAnchor:bubbleView.bottomAnchor constant:-10]\n    ]];\n    \n    // 显示动画\n    bubbleContainer.transform = CGAffineTransformMakeScale(0.5, 0.5);\n    [UIView animateWithDuration:0.3 delay:0 usingSpringWithDamping:0.7 initialSpringVelocity:0.5 options:0 animations:^{\n        bubbleContainer.alpha = 1.0;\n        bubbleContainer.transform = CGAffineTransformIdentity;\n    } completion:^(BOOL finished) {\n        // 自动隐藏\n        dispatch_after(dispatch_time(DISPATCH_TIME_NOW, (int64_t)(duration * NSEC_PER_SEC)), dispatch_get_main_queue(), ^{\n            [UIView animateWithDuration:0.3 animations:^{\n                bubbleContainer.alpha = 0.0;\n                bubbleContainer.transform = CGAffineTransformMakeScale(0.5, 0.5);\n            } completion:^(BOOL finished) {\n                [bubbleContainer removeFromSuperview];\n            }];\n        });\n    }];\n}\n\n// 使用示例\n// showBubblePopup(@\"这是一个气泡提示\", someButton, nil, 3.0);\n"
            },
            @{
                @"title": @"粒子动画弹窗",
                @"description": @"带粒子动画效果的弹窗",
                @"code": @"// 粒子动画弹窗模板\nvoid showParticleAnimationPopup(NSString *title, NSString *message, UIView *parentView, void(^completion)(void)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.7];\n    overlayView.alpha = 0.0;\n    \n    // 创建弹窗容器\n    UIView *popupView = [[UIView alloc] init];\n    popupView.backgroundColor = [UIColor whiteColor];\n    popupView.layer.cornerRadius = 20;\n    popupView.layer.shadowColor = [UIColor blackColor].CGColor;\n    popupView.layer.shadowOffset = CGSizeMake(0, 10);\n    popupView.layer.shadowOpacity = 0.3;\n    popupView.layer.shadowRadius = 20;\n    popupView.transform = CGAffineTransformMakeScale(0.1, 0.1);\n    popupView.alpha = 0.0;\n    \n    // 创建粒子发射器\n    CAEmitterLayer *emitterLayer = [CAEmitterLayer layer];\n    emitterLayer.emitterPosition = CGPointMake(150, 100);\n    emitterLayer.emitterSize = CGSizeMake(300, 200);\n    emitterLayer.emitterShape = kCAEmitterLayerRectangle;\n    emitterLayer.renderMode = kCAEmitterLayerAdditive;\n    \n    // 创建粒子单元\n    CAEmitterCell *emitterCell = [CAEmitterCell emitterCell];\n    emitterCell.birthRate = 50;\n    emitterCell.lifetime = 2.0;\n    emitterCell.velocity = 50;\n    emitterCell.velocityRange = 20;\n    emitterCell.emissionRange = M_PI * 2;\n    emitterCell.scale = 0.1;\n    emitterCell.scaleRange = 0.05;\n    emitterCell.alphaSpeed = -0.5;\n    emitterCell.color = [UIColor systemBlueColor].CGColor;\n    \n    // 创建粒子图像\n    UIGraphicsBeginImageContextWithOptions(CGSizeMake(10, 10), NO, 0);\n    CGContextRef context = UIGraphicsGetCurrentContext();\n    CGContextSetFillColorWithColor(context, [UIColor systemBlueColor].CGColor);\n    CGContextFillEllipseInRect(context, CGRectMake(0, 0, 10, 10));\n    UIImage *particleImage = UIGraphicsGetImageFromCurrentImageContext();\n    UIGraphicsEndImageContext();\n    \n    emitterCell.contents = (id)particleImage.CGImage;\n    emitterLayer.emitterCells = @[emitterCell];\n    \n    // 创建标题\n    UILabel *titleLabel = [[UILabel alloc] init];\n    titleLabel.text = title;\n    titleLabel.font = [UIFont boldSystemFontOfSize:20];\n    titleLabel.textColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0];\n    titleLabel.textAlignment = NSTextAlignmentCenter;\n    titleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建消息\n    UILabel *messageLabel = [[UILabel alloc] init];\n    messageLabel.text = message;\n    messageLabel.font = [UIFont systemFontOfSize:16];\n    messageLabel.textColor = [UIColor colorWithRed:0.4 green:0.4 blue:0.4 alpha:1.0];\n    messageLabel.textAlignment = NSTextAlignmentCenter;\n    messageLabel.numberOfLines = 0;\n    messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建确认按钮\n    UIButton *confirmButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [confirmButton setTitle:@\"太棒了！\" forState:UIControlStateNormal];\n    confirmButton.backgroundColor = [UIColor systemBlueColor];\n    [confirmButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];\n    confirmButton.titleLabel.font = [UIFont boldSystemFontOfSize:16];\n    confirmButton.layer.cornerRadius = 12;\n    confirmButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    [confirmButton addTarget:^{\n        // 停止粒子动画\n        emitterLayer.birthRate = 0;\n        \n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            popupView.transform = CGAffineTransformMakeScale(0.1, 0.1);\n            popupView.alpha = 0.0;\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n            if (completion) completion();\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 添加子视图\n    [popupView.layer addSublayer:emitterLayer];\n    [popupView addSubview:titleLabel];\n    [popupView addSubview:messageLabel];\n    [popupView addSubview:confirmButton];\n    [overlayView addSubview:popupView];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    popupView.translatesAutoresizingMaskIntoConstraints = NO;\n    [NSLayoutConstraint activateConstraints:@[\n        // 弹窗约束\n        [popupView.centerXAnchor constraintEqualToAnchor:overlayView.centerXAnchor],\n        [popupView.centerYAnchor constraintEqualToAnchor:overlayView.centerYAnchor],\n        [popupView.widthAnchor constraintEqualToConstant:300],\n        [popupView.heightAnchor constraintEqualToConstant:200],\n        \n        // 标题约束\n        [titleLabel.topAnchor constraintEqualToAnchor:popupView.topAnchor constant:30],\n        [titleLabel.leadingAnchor constraintEqualToAnchor:popupView.leadingAnchor constant:20],\n        [titleLabel.trailingAnchor constraintEqualToAnchor:popupView.trailingAnchor constant:-20],\n        \n        // 消息约束\n        [messageLabel.topAnchor constraintEqualToAnchor:titleLabel.bottomAnchor constant:15],\n        [messageLabel.leadingAnchor constraintEqualToAnchor:popupView.leadingAnchor constant:20],\n        [messageLabel.trailingAnchor constraintEqualToAnchor:popupView.trailingAnchor constant:-20],\n        \n        // 按钮约束\n        [confirmButton.bottomAnchor constraintEqualToAnchor:popupView.bottomAnchor constant:-20],\n        [confirmButton.centerXAnchor constraintEqualToAnchor:popupView.centerXAnchor],\n        [confirmButton.widthAnchor constraintEqualToConstant:120],\n        [confirmButton.heightAnchor constraintEqualToConstant:40]\n    ]];\n    \n    // 显示动画\n    [UIView animateWithDuration:0.5 delay:0 usingSpringWithDamping:0.6 initialSpringVelocity:0.8 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        popupView.transform = CGAffineTransformIdentity;\n        popupView.alpha = 1.0;\n    } completion:^(BOOL finished) {\n        // 启动粒子动画\n        emitterLayer.birthRate = 50;\n    }];\n}\n\n// 使用示例\n// showParticleAnimationPopup(@\"恭喜！\", @\"操作成功完成！\", nil, ^{\n//     NSLog(@\"用户关闭了粒子动画弹窗\");\n// });\n"
            },
            @{
                @"title": @"翻转卡片弹窗",
                @"description": @"3D翻转效果的卡片弹窗",
                @"code": @"// 翻转卡片弹窗模板\nvoid showFlipCardPopup(NSString *frontTitle, NSString *frontMessage, NSString *backTitle, NSString *backMessage, UIView *parentView, void(^onClose)(void)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.6];\n    overlayView.alpha = 0.0;\n    \n    // 创建卡片容器\n    UIView *cardContainer = [[UIView alloc] init];\n    cardContainer.backgroundColor = [UIColor clearColor];\n    cardContainer.layer.perspectiveDistance = 1000;\n    \n    // 创建正面卡片\n    UIView *frontCard = [[UIView alloc] init];\n    frontCard.backgroundColor = [UIColor colorWithRed:0.2 green:0.6 blue:1.0 alpha:1.0];\n    frontCard.layer.cornerRadius = 15;\n    frontCard.layer.shadowColor = [UIColor blackColor].CGColor;\n    frontCard.layer.shadowOffset = CGSizeMake(0, 5);\n    frontCard.layer.shadowOpacity = 0.3;\n    frontCard.layer.shadowRadius = 10;\n    \n    // 创建背面卡片\n    UIView *backCard = [[UIView alloc] init];\n    backCard.backgroundColor = [UIColor colorWithRed:1.0 green:0.4 blue:0.2 alpha:1.0];\n    backCard.layer.cornerRadius = 15;\n    backCard.layer.shadowColor = [UIColor blackColor].CGColor;\n    backCard.layer.shadowOffset = CGSizeMake(0, 5);\n    backCard.layer.shadowOpacity = 0.3;\n    backCard.layer.shadowRadius = 10;\n    backCard.transform = CATransform3DMakeRotation(M_PI, 0, 1, 0);\n    \n    // 正面内容\n    UILabel *frontTitleLabel = [[UILabel alloc] init];\n    frontTitleLabel.text = frontTitle;\n    frontTitleLabel.font = [UIFont boldSystemFontOfSize:22];\n    frontTitleLabel.textColor = [UIColor whiteColor];\n    frontTitleLabel.textAlignment = NSTextAlignmentCenter;\n    frontTitleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UILabel *frontMessageLabel = [[UILabel alloc] init];\n    frontMessageLabel.text = frontMessage;\n    frontMessageLabel.font = [UIFont systemFontOfSize:16];\n    frontMessageLabel.textColor = [UIColor whiteColor];\n    frontMessageLabel.textAlignment = NSTextAlignmentCenter;\n    frontMessageLabel.numberOfLines = 0;\n    frontMessageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UIButton *flipButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [flipButton setTitle:@\"点击翻转\" forState:UIControlStateNormal];\n    [flipButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];\n    flipButton.titleLabel.font = [UIFont boldSystemFontOfSize:14];\n    flipButton.backgroundColor = [UIColor colorWithRed:1.0 green:1.0 blue:1.0 alpha:0.3];\n    flipButton.layer.cornerRadius = 8;\n    flipButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 背面内容\n    UILabel *backTitleLabel = [[UILabel alloc] init];\n    backTitleLabel.text = backTitle;\n    backTitleLabel.font = [UIFont boldSystemFontOfSize:22];\n    backTitleLabel.textColor = [UIColor whiteColor];\n    backTitleLabel.textAlignment = NSTextAlignmentCenter;\n    backTitleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UILabel *backMessageLabel = [[UILabel alloc] init];\n    backMessageLabel.text = backMessage;\n    backMessageLabel.font = [UIFont systemFontOfSize:16];\n    backMessageLabel.textColor = [UIColor whiteColor];\n    backMessageLabel.textAlignment = NSTextAlignmentCenter;\n    backMessageLabel.numberOfLines = 0;\n    backMessageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    UIButton *closeButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [closeButton setTitle:@\"关闭\" forState:UIControlStateNormal];\n    [closeButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];\n    closeButton.titleLabel.font = [UIFont boldSystemFontOfSize:16];\n    closeButton.backgroundColor = [UIColor colorWithRed:1.0 green:1.0 blue:1.0 alpha:0.3];\n    closeButton.layer.cornerRadius = 8;\n    closeButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 翻转动画\n    __block BOOL isFlipped = NO;\n    [flipButton addTarget:^{\n        [UIView animateWithDuration:0.6 animations:^{\n            if (!isFlipped) {\n                frontCard.layer.transform = CATransform3DMakeRotation(M_PI, 0, 1, 0);\n                backCard.layer.transform = CATransform3DIdentity;\n            } else {\n                frontCard.layer.transform = CATransform3DIdentity;\n                backCard.layer.transform = CATransform3DMakeRotation(M_PI, 0, 1, 0);\n            }\n            isFlipped = !isFlipped;\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 关闭按钮事件\n    [closeButton addTarget:^{\n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            cardContainer.transform = CGAffineTransformMakeScale(0.1, 0.1);\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n            if (onClose) onClose();\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 添加子视图\n    [frontCard addSubview:frontTitleLabel];\n    [frontCard addSubview:frontMessageLabel];\n    [frontCard addSubview:flipButton];\n    \n    [backCard addSubview:backTitleLabel];\n    [backCard addSubview:backMessageLabel];\n    [backCard addSubview:closeButton];\n    \n    [cardContainer addSubview:frontCard];\n    [cardContainer addSubview:backCard];\n    [overlayView addSubview:cardContainer];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    cardContainer.translatesAutoresizingMaskIntoConstraints = NO;\n    frontCard.translatesAutoresizingMaskIntoConstraints = NO;\n    backCard.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    [NSLayoutConstraint activateConstraints:@[\n        // 卡片容器约束\n        [cardContainer.centerXAnchor constraintEqualToAnchor:overlayView.centerXAnchor],\n        [cardContainer.centerYAnchor constraintEqualToAnchor:overlayView.centerYAnchor],\n        [cardContainer.widthAnchor constraintEqualToConstant:280],\n        [cardContainer.heightAnchor constraintEqualToConstant:200],\n        \n        // 正面卡片约束\n        [frontCard.topAnchor constraintEqualToAnchor:cardContainer.topAnchor],\n        [frontCard.leadingAnchor constraintEqualToAnchor:cardContainer.leadingAnchor],\n        [frontCard.trailingAnchor constraintEqualToAnchor:cardContainer.trailingAnchor],\n        [frontCard.bottomAnchor constraintEqualToAnchor:cardContainer.bottomAnchor],\n        \n        // 背面卡片约束\n        [backCard.topAnchor constraintEqualToAnchor:cardContainer.topAnchor],\n        [backCard.leadingAnchor constraintEqualToAnchor:cardContainer.leadingAnchor],\n        [backCard.trailingAnchor constraintEqualToAnchor:cardContainer.trailingAnchor],\n        [backCard.bottomAnchor constraintEqualToAnchor:cardContainer.bottomAnchor],\n        \n        // 正面内容约束\n        [frontTitleLabel.topAnchor constraintEqualToAnchor:frontCard.topAnchor constant:30],\n        [frontTitleLabel.leadingAnchor constraintEqualToAnchor:frontCard.leadingAnchor constant:20],\n        [frontTitleLabel.trailingAnchor constraintEqualToAnchor:frontCard.trailingAnchor constant:-20],\n        \n        [frontMessageLabel.topAnchor constraintEqualToAnchor:frontTitleLabel.bottomAnchor constant:15],\n        [frontMessageLabel.leadingAnchor constraintEqualToAnchor:frontCard.leadingAnchor constant:20],\n        [frontMessageLabel.trailingAnchor constraintEqualToAnchor:frontCard.trailingAnchor constant:-20],\n        \n        [flipButton.bottomAnchor constraintEqualToAnchor:frontCard.bottomAnchor constant:-20],\n        [flipButton.centerXAnchor constraintEqualToAnchor:frontCard.centerXAnchor],\n        [flipButton.widthAnchor constraintEqualToConstant:100],\n        [flipButton.heightAnchor constraintEqualToConstant:35],\n        \n        // 背面内容约束\n        [backTitleLabel.topAnchor constraintEqualToAnchor:backCard.topAnchor constant:30],\n        [backTitleLabel.leadingAnchor constraintEqualToAnchor:backCard.leadingAnchor constant:20],\n        [backTitleLabel.trailingAnchor constraintEqualToAnchor:backCard.trailingAnchor constant:-20],\n        \n        [backMessageLabel.topAnchor constraintEqualToAnchor:backTitleLabel.bottomAnchor constant:15],\n        [backMessageLabel.leadingAnchor constraintEqualToAnchor:backCard.leadingAnchor constant:20],\n        [backMessageLabel.trailingAnchor constraintEqualToAnchor:backCard.trailingAnchor constant:-20],\n        \n        [closeButton.bottomAnchor constraintEqualToAnchor:backCard.bottomAnchor constant:-20],\n        [closeButton.centerXAnchor constraintEqualToAnchor:backCard.centerXAnchor],\n        [closeButton.widthAnchor constraintEqualToConstant:100],\n        [closeButton.heightAnchor constraintEqualToConstant:35]\n    ]];\n    \n    // 初始状态\n    cardContainer.transform = CGAffineTransformMakeScale(0.1, 0.1);\n    \n    // 显示动画\n    [UIView animateWithDuration:0.5 delay:0 usingSpringWithDamping:0.7 initialSpringVelocity:0.5 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        cardContainer.transform = CGAffineTransformIdentity;\n    } completion:nil];\n}\n\n// 使用示例\n// showFlipCardPopup(@\"正面标题\", @\"这是正面的内容\", @\"背面标题\", @\"这是背面的详细信息\", nil, ^{\n//     NSLog(@\"用户关闭了翻转卡片弹窗\");\n// });\n"
            },
            @{
                @"title": @"波纹扩散弹窗",
                @"description": @"带波纹扩散动画的弹窗",
                @"code": @"// 波纹扩散弹窗模板\nvoid showRipplePopup(NSString *title, NSString *message, UIView *parentView, void(^onConfirm)(void)) {\n    if (!parentView) {\n        parentView = [UIApplication sharedApplication].keyWindow;\n    }\n    \n    // 创建背景遮罩\n    UIView *overlayView = [[UIView alloc] initWithFrame:parentView.bounds];\n    overlayView.backgroundColor = [UIColor colorWithRed:0.0 green:0.0 blue:0.0 alpha:0.6];\n    overlayView.alpha = 0.0;\n    \n    // 创建波纹容器\n    UIView *rippleContainer = [[UIView alloc] init];\n    rippleContainer.backgroundColor = [UIColor clearColor];\n    rippleContainer.clipsToBounds = NO;\n    \n    // 创建弹窗主体\n    UIView *popupView = [[UIView alloc] init];\n    popupView.backgroundColor = [UIColor whiteColor];\n    popupView.layer.cornerRadius = 20;\n    popupView.layer.shadowColor = [UIColor blackColor].CGColor;\n    popupView.layer.shadowOffset = CGSizeMake(0, 10);\n    popupView.layer.shadowOpacity = 0.3;\n    popupView.layer.shadowRadius = 20;\n    popupView.transform = CGAffineTransformMakeScale(0.1, 0.1);\n    popupView.alpha = 0.0;\n    \n    // 创建波纹动画层\n    NSMutableArray *rippleLayers = [NSMutableArray array];\n    for (int i = 0; i < 3; i++) {\n        CAShapeLayer *rippleLayer = [CAShapeLayer layer];\n        rippleLayer.strokeColor = [UIColor systemBlueColor].CGColor;\n        rippleLayer.fillColor = [UIColor clearColor].CGColor;\n        rippleLayer.lineWidth = 2.0;\n        rippleLayer.opacity = 0.0;\n        \n        UIBezierPath *circlePath = [UIBezierPath bezierPathWithOvalInRect:CGRectMake(-150, -100, 300, 200)];\n        rippleLayer.path = circlePath.CGPath;\n        \n        [rippleContainer.layer addSublayer:rippleLayer];\n        [rippleLayers addObject:rippleLayer];\n    }\n    \n    // 创建标题\n    UILabel *titleLabel = [[UILabel alloc] init];\n    titleLabel.text = title;\n    titleLabel.font = [UIFont boldSystemFontOfSize:22];\n    titleLabel.textColor = [UIColor colorWithRed:0.2 green:0.2 blue:0.2 alpha:1.0];\n    titleLabel.textAlignment = NSTextAlignmentCenter;\n    titleLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建消息\n    UILabel *messageLabel = [[UILabel alloc] init];\n    messageLabel.text = message;\n    messageLabel.font = [UIFont systemFontOfSize:16];\n    messageLabel.textColor = [UIColor colorWithRed:0.4 green:0.4 blue:0.4 alpha:1.0];\n    messageLabel.textAlignment = NSTextAlignmentCenter;\n    messageLabel.numberOfLines = 0;\n    messageLabel.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 创建确认按钮\n    UIButton *confirmButton = [UIButton buttonWithType:UIButtonTypeSystem];\n    [confirmButton setTitle:@\"确认\" forState:UIControlStateNormal];\n    confirmButton.backgroundColor = [UIColor systemBlueColor];\n    [confirmButton setTitleColor:[UIColor whiteColor] forState:UIControlStateNormal];\n    confirmButton.titleLabel.font = [UIFont boldSystemFontOfSize:16];\n    confirmButton.layer.cornerRadius = 12;\n    confirmButton.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    // 波纹动画\n    void (^startRippleAnimation)(void) = ^{\n        for (int i = 0; i < rippleLayers.count; i++) {\n            CAShapeLayer *rippleLayer = rippleLayers[i];\n            \n            // 缩放动画\n            CABasicAnimation *scaleAnimation = [CABasicAnimation animationWithKeyPath:@\"transform.scale\"];\n            scaleAnimation.fromValue = @0.0;\n            scaleAnimation.toValue = @2.0;\n            scaleAnimation.duration = 2.0;\n            scaleAnimation.beginTime = CACurrentMediaTime() + i * 0.3;\n            scaleAnimation.repeatCount = HUGE_VALF;\n            \n            // 透明度动画\n            CABasicAnimation *opacityAnimation = [CABasicAnimation animationWithKeyPath:@\"opacity\"];\n            opacityAnimation.fromValue = @0.8;\n            opacityAnimation.toValue = @0.0;\n            opacityAnimation.duration = 2.0;\n            opacityAnimation.beginTime = CACurrentMediaTime() + i * 0.3;\n            opacityAnimation.repeatCount = HUGE_VALF;\n            \n            [rippleLayer addAnimation:scaleAnimation forKey:@\"scale\"];\n            [rippleLayer addAnimation:opacityAnimation forKey:@\"opacity\"];\n        }\n    };\n    \n    // 确认按钮事件\n    [confirmButton addTarget:^{\n        // 停止波纹动画\n        for (CAShapeLayer *rippleLayer in rippleLayers) {\n            [rippleLayer removeAllAnimations];\n        }\n        \n        [UIView animateWithDuration:0.3 animations:^{\n            overlayView.alpha = 0.0;\n            popupView.transform = CGAffineTransformMakeScale(0.1, 0.1);\n            popupView.alpha = 0.0;\n        } completion:^(BOOL finished) {\n            [overlayView removeFromSuperview];\n            if (onConfirm) onConfirm();\n        }];\n    } forControlEvents:UIControlEventTouchUpInside];\n    \n    // 添加子视图\n    [popupView addSubview:titleLabel];\n    [popupView addSubview:messageLabel];\n    [popupView addSubview:confirmButton];\n    [rippleContainer addSubview:popupView];\n    [overlayView addSubview:rippleContainer];\n    [parentView addSubview:overlayView];\n    \n    // 设置约束\n    rippleContainer.translatesAutoresizingMaskIntoConstraints = NO;\n    popupView.translatesAutoresizingMaskIntoConstraints = NO;\n    \n    [NSLayoutConstraint activateConstraints:@[\n        // 波纹容器约束\n        [rippleContainer.centerXAnchor constraintEqualToAnchor:overlayView.centerXAnchor],\n        [rippleContainer.centerYAnchor constraintEqualToAnchor:overlayView.centerYAnchor],\n        [rippleContainer.widthAnchor constraintEqualToConstant:300],\n        [rippleContainer.heightAnchor constraintEqualToConstant:200],\n        \n        // 弹窗约束\n        [popupView.centerXAnchor constraintEqualToAnchor:rippleContainer.centerXAnchor],\n        [popupView.centerYAnchor constraintEqualToAnchor:rippleContainer.centerYAnchor],\n        [popupView.widthAnchor constraintEqualToConstant:280],\n        [popupView.heightAnchor constraintEqualToConstant:180],\n        \n        // 标题约束\n        [titleLabel.topAnchor constraintEqualToAnchor:popupView.topAnchor constant:25],\n        [titleLabel.leadingAnchor constraintEqualToAnchor:popupView.leadingAnchor constant:20],\n        [titleLabel.trailingAnchor constraintEqualToAnchor:popupView.trailingAnchor constant:-20],\n        \n        // 消息约束\n        [messageLabel.topAnchor constraintEqualToAnchor:titleLabel.bottomAnchor constant:15],\n        [messageLabel.leadingAnchor constraintEqualToAnchor:popupView.leadingAnchor constant:20],\n        [messageLabel.trailingAnchor constraintEqualToAnchor:popupView.trailingAnchor constant:-20],\n        \n        // 按钮约束\n        [confirmButton.bottomAnchor constraintEqualToAnchor:popupView.bottomAnchor constant:-20],\n        [confirmButton.centerXAnchor constraintEqualToAnchor:popupView.centerXAnchor],\n        [confirmButton.widthAnchor constraintEqualToConstant:120],\n        [confirmButton.heightAnchor constraintEqualToConstant:40]\n    ]];\n    \n    // 显示动画\n    [UIView animateWithDuration:0.5 delay:0 usingSpringWithDamping:0.7 initialSpringVelocity:0.5 options:0 animations:^{\n        overlayView.alpha = 1.0;\n        popupView.transform = CGAffineTransformIdentity;\n        popupView.alpha = 1.0;\n    } completion:^(BOOL finished) {\n        // 启动波纹动画\n        startRippleAnimation();\n    }];\n}\n\n// 使用示例\n// showRipplePopup(@\"提示\", @\"这是一个带波纹动画的弹窗\", nil, ^{\n//     NSLog(@\"用户确认了波纹弹窗\");\n// });\n"
            }
        ],
        @"高级逆向": @[
            @{
                @"title": @"反调试检测绕过",
                @"description": @"绕过常见的反调试检测",
                @"code": @"// 反调试检测绕过模板\n#import <sys/sysctl.h>\n#import <dlfcn.h>\n\n// Hook ptrace函数\nint (*original_ptrace)(int request, pid_t pid, caddr_t addr, int data);\nint replaced_ptrace(int request, pid_t pid, caddr_t addr, int data) {\n    if (request == 31) { // PT_DENY_ATTACH\n        NSLog(@\"[ANTI-DEBUG] Blocked PT_DENY_ATTACH\");\n        return 0;\n    }\n    return original_ptrace(request, pid, addr, data);\n}\n\n// Hook sysctl函数\nint (*original_sysctl)(int *name, u_int namelen, void *oldp, size_t *oldlenp, void *newp, size_t newlen);\nint replaced_sysctl(int *name, u_int namelen, void *oldp, size_t *oldlenp, void *newp, size_t newlen) {\n    if (namelen == 4 && name[0] == 1 && name[1] == 14 && name[2] == 1) {\n        // 检测调试器的sysctl调用\n        int ret = original_sysctl(name, namelen, oldp, oldlenp, newp, newlen);\n        if (oldp) {\n            struct kinfo_proc *info = (struct kinfo_proc *)oldp;\n            info->kp_proc.p_flag &= ~P_TRACED; // 清除调试标志\n            NSLog(@\"[ANTI-DEBUG] Cleared P_TRACED flag\");\n        }\n        return ret;\n    }\n    return original_sysctl(name, namelen, oldp, oldlenp, newp, newlen);\n}\n\n%ctor {\n    // Hook ptrace\n    void *handle = dlopen(NULL, RTLD_LAZY);\n    original_ptrace = dlsym(handle, \"ptrace\");\n    MSHookFunction(original_ptrace, replaced_ptrace, (void **)&original_ptrace);\n    \n    // Hook sysctl\n    original_sysctl = dlsym(handle, \"sysctl\");\n    MSHookFunction(original_sysctl, replaced_sysctl, (void **)&original_sysctl);\n    \n    NSLog(@\"[ANTI-DEBUG] Anti-debugging hooks installed\");\n}\n"
            },
            @{
                @"title": @"SSL Pinning绕过",
                @"description": @"绕过SSL证书绑定检查",
                @"code": @"// SSL Pinning绕过模板\n%hook NSURLSession\n\n- (void)URLSession:(NSURLSession *)session didReceiveChallenge:(NSURLAuthenticationChallenge *)challenge completionHandler:(void (^)(NSURLSessionAuthChallengeDisposition, NSURLCredential *))completionHandler {\n    NSLog(@\"[SSL] Bypassing SSL pinning for: %@\", challenge.protectionSpace.host);\n    \n    // 创建信任所有证书的凭据\n    NSURLCredential *credential = [NSURLCredential credentialForTrust:challenge.protectionSpace.serverTrust];\n    completionHandler(NSURLSessionAuthChallengeUseCredential, credential);\n}\n\n%end\n\n%hook NSURLConnection\n\n+ (BOOL)canHandleRequest:(NSURLRequest *)request {\n    NSLog(@\"[SSL] NSURLConnection handling: %@\", request.URL);\n    return %orig;\n}\n\n- (void)connection:(NSURLConnection *)connection didReceiveAuthenticationChallenge:(NSURLAuthenticationChallenge *)challenge {\n    NSLog(@\"[SSL] Bypassing SSL pinning for NSURLConnection: %@\", challenge.protectionSpace.host);\n    \n    NSURLCredential *credential = [NSURLCredential credentialForTrust:challenge.protectionSpace.serverTrust];\n    [challenge.sender useCredential:credential forAuthenticationChallenge:challenge];\n}\n\n%end\n\n// Hook AFNetworking (如果应用使用)\n%hook AFSecurityPolicy\n\n- (BOOL)evaluateServerTrust:(SecTrustRef)serverTrust forDomain:(NSString *)domain {\n    NSLog(@\"[SSL] AFNetworking SSL bypass for domain: %@\", domain);\n    return YES; // 总是返回YES，绕过SSL验证\n}\n\n%end\n"
            },
            @{
                @"title": @"越狱检测绕过",
                @"description": @"绕过常见的越狱检测方法",
                @"code": @"// 越狱检测绕过模板\n%hook NSFileManager\n\n- (BOOL)fileExistsAtPath:(NSString *)path {\n    // 常见的越狱文件路径\n    NSArray *jailbreakPaths = @[\n        @\"/Applications/Cydia.app\",\n        @\"/Library/MobileSubstrate/MobileSubstrate.dylib\",\n        @\"/bin/bash\",\n        @\"/usr/sbin/sshd\",\n        @\"/etc/apt\",\n        @\"/private/var/lib/apt/\",\n        @\"/private/var/lib/cydia\",\n        @\"/private/var/stash\",\n        @\"/usr/libexec/ssh-keysign\",\n        @\"/var/cache/apt\",\n        @\"/var/lib/cydia\",\n        @\"/usr/bin/sshd\",\n        @\"/usr/libexec/sftp-server\",\n        @\"/Applications/blackra1n.app\",\n        @\"/Applications/FakeCarrier.app\",\n        @\"/Applications/Icy.app\",\n        @\"/Applications/IntelliScreen.app\",\n        @\"/Applications/MxTube.app\",\n        @\"/Applications/RockApp.app\",\n        @\"/Applications/SBSettings.app\",\n        @\"/Applications/WinterBoard.app\"\n    ];\n    \n    for (NSString *jailbreakPath in jailbreakPaths) {\n        if ([path isEqualToString:jailbreakPath]) {\n            NSLog(@\"[JAILBREAK] Blocked detection of: %@\", path);\n            return NO; // 返回NO，假装文件不存在\n        }\n    }\n    \n    return %orig;\n}\n\n- (BOOL)isReadableFileAtPath:(NSString *)path {\n    NSArray *jailbreakPaths = @[\n        @\"/Applications/Cydia.app\",\n        @\"/Library/MobileSubstrate/MobileSubstrate.dylib\",\n        @\"/bin/bash\",\n        @\"/usr/sbin/sshd\",\n        @\"/etc/apt\"\n    ];\n    \n    for (NSString *jailbreakPath in jailbreakPaths) {\n        if ([path isEqualToString:jailbreakPath]) {\n            NSLog(@\"[JAILBREAK] Blocked readable check for: %@\", path);\n            return NO;\n        }\n    }\n    \n    return %orig;\n}\n\n%end\n\n// Hook stat函数\n#import <sys/stat.h>\nint (*original_stat)(const char *path, struct stat *buf);\nint replaced_stat(const char *path, struct stat *buf) {\n    NSString *pathString = [NSString stringWithUTF8String:path];\n    \n    NSArray *jailbreakPaths = @[\n        @\"/Applications/Cydia.app\",\n        @\"/Library/MobileSubstrate/MobileSubstrate.dylib\",\n        @\"/bin/bash\",\n        @\"/usr/sbin/sshd\",\n        @\"/etc/apt\"\n    ];\n    \n    for (NSString *jailbreakPath in jailbreakPaths) {\n        if ([pathString isEqualToString:jailbreakPath]) {\n            NSLog(@\"[JAILBREAK] Blocked stat() for: %@\", pathString);\n            return -1; // 返回-1表示文件不存在\n        }\n    }\n    \n    return original_stat(path, buf);\n}\n\n%ctor {\n    // Hook stat函数\n    MSHookFunction(stat, replaced_stat, (void **)&original_stat);\n    NSLog(@\"[JAILBREAK] Jailbreak detection bypass installed\");\n}\n"
            },
            @{
                @"title": @"动态库注入检测",
                @"description": @"检测和分析动态库注入",
                @"code": @"// 动态库注入检测模板\n#import <mach-o/dyld.h>\n#import <dlfcn.h>\n\n%hook NSBundle\n\n+ (NSBundle *)mainBundle {\n    NSBundle *bundle = %orig;\n    \n    // 获取主程序路径\n    NSString *executablePath = bundle.executablePath;\n    NSLog(@\"[DYLIB] Main executable: %@\", executablePath);\n    \n    // 枚举所有加载的动态库\n    uint32_t count = _dyld_image_count();\n    NSLog(@\"[DYLIB] Total loaded images: %d\", count);\n    \n    for (uint32_t i = 0; i < count; i++) {\n        const char *imageName = _dyld_get_image_name(i);\n        const struct mach_header *header = _dyld_get_image_header(i);\n        intptr_t slide = _dyld_get_image_vmaddr_slide(i);\n        \n        NSString *imageNameStr = [NSString stringWithUTF8String:imageName];\n        NSLog(@\"[DYLIB] Image %d: %@ (Header: %p, Slide: 0x%lx)\", i, imageNameStr, header, slide);\n        \n        // 检测可疑的动态库\n        if ([imageNameStr containsString:@\"MobileSubstrate\"] ||\n            [imageNameStr containsString:@\"CydiaSubstrate\"] ||\n            [imageNameStr containsString:@\"substitute\"] ||\n            [imageNameStr containsString:@\"frida\"]) {\n            NSLog(@\"[DYLIB] ⚠️ Suspicious library detected: %@\", imageNameStr);\n        }\n    }\n    \n    return bundle;\n}\n\n%end\n\n// Hook dlopen函数\nvoid* (*original_dlopen)(const char* path, int mode);\nvoid* replaced_dlopen(const char* path, int mode) {\n    if (path) {\n        NSString *pathStr = [NSString stringWithUTF8String:path];\n        NSLog(@\"[DYLIB] dlopen called for: %@\", pathStr);\n        \n        // 检测动态加载的库\n        if ([pathStr containsString:@\"MobileSubstrate\"] ||\n            [pathStr containsString:@\"CydiaSubstrate\"]) {\n            NSLog(@\"[DYLIB] ⚠️ Substrate library being loaded: %@\", pathStr);\n        }\n    }\n    \n    return original_dlopen(path, mode);\n}\n\n// Hook dlsym函数\nvoid* (*original_dlsym)(void* handle, const char* symbol);\nvoid* replaced_dlsym(void* handle, const char* symbol) {\n    if (symbol) {\n        NSString *symbolStr = [NSString stringWithUTF8String:symbol];\n        \n        // 记录敏感符号查找\n        if ([symbolStr containsString:@\"MSHook\"] ||\n            [symbolStr containsString:@\"substrate\"] ||\n            [symbolStr containsString:@\"ptrace\"]) {\n            NSLog(@\"[DYLIB] ⚠️ Sensitive symbol lookup: %@\", symbolStr);\n        }\n    }\n    \n    return original_dlsym(handle, symbol);\n}\n\n%ctor {\n    // Hook dlopen和dlsym\n    MSHookFunction(dlopen, replaced_dlopen, (void **)&original_dlopen);\n    MSHookFunction(dlsym, replaced_dlsym, (void **)&original_dlsym);\n    \n    NSLog(@\"[DYLIB] Dynamic library monitoring installed\");\n}\n"
            },
            @{
                @"title": @"内存修改检测",
                @"description": @"检测内存修改和代码注入",
                @"code": @"// 内存修改检测模板\n#import <mach/mach.h>\n#import <mach/vm_map.h>\n#import <mach/vm_region.h>\n\n// 检查内存区域\nvoid checkMemoryRegions() {\n    task_t task = mach_task_self();\n    vm_address_t address = 0;\n    vm_size_t size = 0;\n    vm_region_flavor_t flavor = VM_REGION_BASIC_INFO_64;\n    vm_region_basic_info_data_64_t info;\n    mach_msg_type_number_t info_count = VM_REGION_BASIC_INFO_COUNT_64;\n    memory_object_name_t object;\n    \n    NSLog(@\"[MEMORY] Starting memory region analysis...\");\n    \n    while (vm_region_64(task, &address, &size, flavor, (vm_region_info_t)&info, &info_count, &object) == KERN_SUCCESS) {\n        \n        // 检查可执行内存区域\n        if (info.protection & VM_PROT_EXECUTE) {\n            NSLog(@\"[MEMORY] Executable region: 0x%lx - 0x%lx (Size: %lu KB)\", \n                  (unsigned long)address, \n                  (unsigned long)(address + size), \n                  (unsigned long)(size / 1024));\n            \n            // 检查是否为可疑的内存区域\n            if (info.protection & VM_PROT_WRITE) {\n                NSLog(@\"[MEMORY] ⚠️ Writable executable memory detected at: 0x%lx\", (unsigned long)address);\n            }\n        }\n        \n        address += size;\n    }\n}\n\n// Hook mprotect函数\nint (*original_mprotect)(void *addr, size_t len, int prot);\nint replaced_mprotect(void *addr, size_t len, int prot) {\n    NSLog(@\"[MEMORY] mprotect called: addr=0x%p, len=%zu, prot=0x%x\", addr, len, prot);\n    \n    // 检查是否在修改内存保护属性\n    if (prot & PROT_EXEC) {\n        NSLog(@\"[MEMORY] ⚠️ Making memory executable at: 0x%p\", addr);\n        \n        if (prot & PROT_WRITE) {\n            NSLog(@\"[MEMORY] ⚠️ Making memory writable AND executable at: 0x%p\", addr);\n        }\n    }\n    \n    return original_mprotect(addr, len, prot);\n}\n\n// Hook mmap函数\nvoid* (*original_mmap)(void *addr, size_t length, int prot, int flags, int fd, off_t offset);\nvoid* replaced_mmap(void *addr, size_t length, int prot, int flags, int fd, off_t offset) {\n    void *result = original_mmap(addr, length, prot, flags, fd, offset);\n    \n    if (result != MAP_FAILED) {\n        NSLog(@\"[MEMORY] mmap: addr=0x%p, length=%zu, prot=0x%x, result=0x%p\", addr, length, prot, result);\n        \n        if (prot & PROT_EXEC) {\n            NSLog(@\"[MEMORY] ⚠️ Executable memory mapped at: 0x%p\", result);\n        }\n    }\n    \n    return result;\n}\n\n%ctor {\n    // Hook内存相关函数\n    MSHookFunction(mprotect, replaced_mprotect, (void **)&original_mprotect);\n    MSHookFunction(mmap, replaced_mmap, (void **)&original_mmap);\n    \n    // 定期检查内存区域\n    dispatch_async(dispatch_get_global_queue(DISPATCH_QUEUE_PRIORITY_LOW, 0), ^{\n        while (true) {\n            checkMemoryRegions();\n            sleep(30); // 每30秒检查一次\n        }\n    });\n    \n    NSLog(@\"[MEMORY] Memory modification monitoring installed\");\n}\n"
            }
        ]
    };
}

- (NSArray<NSDictionary *> *)getTemplatesForFileExtension:(NSString *)fileExtension {
    if (![fileExtension isEqualToString:@"xm"] && ![fileExtension isEqualToString:@"mm"]) {
        return @[];
    }
    
    NSMutableArray *allTemplates = [NSMutableArray array];
    
    for (NSString *category in self.templates.allKeys) {
        NSArray *categoryTemplates = self.templates[category];
        [allTemplates addObjectsFromArray:categoryTemplates];
    }
    
    return [allTemplates copy];
}

- (NSDictionary *)getAllTemplates {
    return self.templates;
}

@end
